import{c as r,Q as a,j as t,m as s}from"./chunks/framework.DVkeSyfh.js";const p=JSON.parse('{"title":"Similarity scores","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/similarity-scores.md","filePath":"concepts/similarity-scores.md","lastUpdated":null}'),i={name:"concepts/similarity-scores.md"};function o(n,e,c,l,d,m){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="similarity-scores" tabindex="-1">Similarity scores <a class="header-anchor" href="#similarity-scores" aria-label="Permalink to &quot;Similarity scores&quot;">​</a></h1><p>Audience: users reading ranked results<br> Goal: explain what scores can and cannot mean<br> Type: explanation</p><p>Similarity scores are ranking hints. They help sort candidates, but they are not objective judgments of musical quality or transition success.</p><h2 id="why-scores-differ" tabindex="-1">Why scores differ <a class="header-anchor" href="#why-scores-differ" aria-label="Permalink to &quot;Why scores differ&quot;">​</a></h2><p>Different search modes answer different questions:</p><ul><li>SONARA compares analyzed feature rows.</li><li>MERT compares audio embeddings from selected seeds.</li><li>CLAP compares text prompts or CLAP signals against stored embeddings.</li><li>CLASS uses promoted classifier probabilities.</li><li>SET combines several signals and then orders a route with constraints.</li></ul><p>The same track can rank differently across these modes.</p><h2 id="do-not-compare-every-number-directly" tabindex="-1">Do not compare every number directly <a class="header-anchor" href="#do-not-compare-every-number-directly" aria-label="Permalink to &quot;Do not compare every number directly&quot;">​</a></h2><p>A high score in one mode is not automatically stronger than a lower-looking score in another mode. Treat each result list in the context of its own search method.</p><h2 id="listen-before-exporting" tabindex="-1">Listen before exporting <a class="header-anchor" href="#listen-before-exporting" aria-label="Permalink to &quot;Listen before exporting&quot;">​</a></h2><p>Use scores to reduce the search space. Use your ears and DJ judgement to decide whether the track actually belongs in the set or crate.</p>',11)])])}const u=r(i,[["render",o]]);export{p as __pageData,u as default};
